import { useParams } from "react-router-dom";
import { useEffect, useState } from "react";
import { GetFixtureGameStats } from "../services/game-stat-service";
import { GameStat } from "../objects/game-stat";
import GameStatTable from "../components/game-stats/game-stat-table";
import { GetFixture } from "../services/fixture-service";
import { Fixture } from "../objects/fixture";
import FixtureTable from "../components/fixture/fixture-table";
import { GameType } from "../objects/enums/enums";

export default function FixturePage()
{
    const param = useParams();
    const [fixtures, setFixtures] = useState<Fixture[] | null>(null);
    const [gameStats, setGameStats] = useState<GameStat[] | null>(null);
    
    useEffect(() => {
        GetFixture(param.id).then(fixture => setFixtures(fixture));
        //GetFixtureGameStats(param.id).then(gameStats => setGameStats(gameStats));
    }, []);  
    
    return(   
        <>
            <div>
                <div className="row">
                    {   fixtures ? <FixtureTable fixtures={fixtures} gameType={GameType.Any}></FixtureTable> 
                        : <p>Loading Fixture...</p>}
                </div>
            </div>
            
            <div>
                <div className="row">
                    {   gameStats ? <GameStatTable gameStats={gameStats}></GameStatTable>
                        : <p>Loading Stats...</p>}
                </div>
            </div>  
        </>              
    )
}
